local key = _G.OLLIE_KEY


local function bxor(a, b)
    local r = 0 local bit = 1
    while a > 0 or b > 0 do
        local ab = a % 2
        local bb = b % 2
        if ab ~= bb then r = r + bit end
        a = math.floor(a / 2); b = math.floor(b / 2)
        bit = bit * 2
    end
    return r
end


local function from_hex(hex)
    local bytes = {}
    for i = 1, #hex, 2 do
        local byte = tonumber(hex:sub(i, i+1), 16)
        bytes[#bytes+1] = string.char(byte)
    end
    return table.concat(bytes)
end


local function position_unscramble(data)
    local res = {}
    for i = 1, #data do
        local byte = data:byte(i)
        local shift = (i % 13) + 3
        byte = (byte - shift) % 256
        res[i] = string.char(byte)
    end
    return table.concat(res)
end


local function recover_key(stored_hex)
    local bin = from_hex(stored_hex)
    local unxored = ""
    for i = 1, #bin do
        unxored = unxored .. string.char(bxor(bin:byte(i), 0x5A))
    end
    return string.reverse(unxored)
end


local function decode(data, key)
    local res = {}
    for i = 1, #data do
        local c = data:byte(i)
        local k = key:byte((i - 1) % #key + 1)
        res[i] = string.char(bxor(c, k))
    end
    return table.concat(res)
end


